<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Kanban Board</title>
<style>
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

  body {
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    background: #0f172a;
    color: #e2e8f0;
    min-height: 100vh;
    padding: 32px 24px;
  }

  h1 {
    text-align: center;
    font-size: 1.75rem;
    font-weight: 700;
    letter-spacing: -0.02em;
    margin-bottom: 28px;
    color: #f8fafc;
  }

  .add-row {
    display: flex;
    gap: 8px;
    max-width: 420px;
    margin: 0 auto 36px;
  }

  #new-card {
    flex: 1;
    padding: 10px 14px;
    border-radius: 8px;
    border: 1.5px solid #334155;
    background: #1e293b;
    color: #f1f5f9;
    font-size: 0.95rem;
    outline: none;
    transition: border-color 0.15s;
  }
  #new-card::placeholder { color: #64748b; }
  #new-card:focus { border-color: #6366f1; }

  #add-card {
    padding: 10px 18px;
    border-radius: 8px;
    border: none;
    background: #6366f1;
    color: #fff;
    font-size: 0.95rem;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.15s, transform 0.1s;
    white-space: nowrap;
  }
  #add-card:hover { background: #4f46e5; }
  #add-card:active { transform: scale(0.97); }

  .board {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 20px;
    max-width: 1080px;
    margin: 0 auto;
    align-items: start;
  }

  .column {
    background: #1e293b;
    border-radius: 14px;
    padding: 16px;
    min-height: 480px;
    border: 1.5px solid #334155;
    transition: border-color 0.15s;
  }
  .column.drag-over {
    border-color: #6366f1;
    background: #1e2f4a;
  }

  .col-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    margin-bottom: 14px;
    padding-bottom: 12px;
    border-bottom: 1.5px solid #334155;
  }

  .col-title {
    font-size: 0.85rem;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.07em;
    color: #94a3b8;
  }

  #col-todo .col-title  { color: #f59e0b; }
  #col-doing .col-title { color: #6366f1; }
  #col-done .col-title  { color: #22c55e; }

  .count {
    font-size: 0.78rem;
    font-weight: 700;
    background: #334155;
    color: #94a3b8;
    border-radius: 999px;
    padding: 2px 9px;
    min-width: 24px;
    text-align: center;
  }

  .card-container {
    display: flex;
    flex-direction: column;
    gap: 10px;
    min-height: 60px;
  }

  .card {
    background: #0f172a;
    border: 1.5px solid #334155;
    border-radius: 10px;
    padding: 12px 14px;
    display: flex;
    align-items: flex-start;
    justify-content: space-between;
    gap: 10px;
    cursor: grab;
    user-select: none;
    transition: box-shadow 0.15s, border-color 0.15s, transform 0.1s;
    word-break: break-word;
  }
  .card:hover {
    border-color: #475569;
    box-shadow: 0 4px 16px rgba(0,0,0,0.35);
  }
  .card.dragging {
    opacity: 0.4;
    transform: scale(0.97);
    cursor: grabbing;
  }

  .card-title {
    font-size: 0.92rem;
    line-height: 1.45;
    color: #e2e8f0;
    flex: 1;
  }

  .card-del {
    flex-shrink: 0;
    background: none;
    border: none;
    color: #475569;
    cursor: pointer;
    font-size: 1.05rem;
    line-height: 1;
    padding: 2px 4px;
    border-radius: 4px;
    transition: color 0.12s, background 0.12s;
  }
  .card-del:hover { color: #f87171; background: #1e293b; }

  @media (max-width: 680px) {
    .board { grid-template-columns: 1fr; }
  }
</style>
</head>
<body>
<h1>Kanban Board</h1>

<div class="add-row">
  <input id="new-card" type="text" placeholder="New card title…" maxlength="200">
  <button id="add-card">Add Card</button>
</div>

<div class="board">
  <div class="column" id="col-todo">
    <div class="col-header">
      <span class="col-title">To Do</span>
      <span class="count">0</span>
    </div>
    <div class="card-container"></div>
  </div>
  <div class="column" id="col-doing">
    <div class="col-header">
      <span class="col-title">In Progress</span>
      <span class="count">0</span>
    </div>
    <div class="card-container"></div>
  </div>
  <div class="column" id="col-done">
    <div class="col-header">
      <span class="col-title">Done</span>
      <span class="count">0</span>
    </div>
    <div class="card-container"></div>
  </div>
</div>

<script>
  const STORAGE_KEY = 'kanban-v1';
  let draggingCard = null;

  function getContainers() {
    return {
      'col-todo':  document.querySelector('#col-todo  .card-container'),
      'col-doing': document.querySelector('#col-doing .card-container'),
      'col-done':  document.querySelector('#col-done  .card-container'),
    };
  }

  function updateCount(colEl) {
    const n = colEl.querySelectorAll('.card').length;
    colEl.querySelector('.count').textContent = n;
  }

  function saveState() {
    const cols = getContainers();
    const data = {};
    for (const [colId, container] of Object.entries(cols)) {
      data[colId] = [...container.querySelectorAll('.card')].map(c => ({
        id: c.dataset.id,
        title: c.querySelector('.card-title').textContent,
      }));
    }
    localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
  }

  function createCardEl(id, title) {
    const card = document.createElement('div');
    card.className = 'card';
    card.draggable = true;
    card.dataset.id = id;

    const titleEl = document.createElement('span');
    titleEl.className = 'card-title';
    titleEl.textContent = title;

    const delBtn = document.createElement('button');
    delBtn.className = 'card-del';
    delBtn.setAttribute('aria-label', 'Delete card');
    delBtn.textContent = '✕';
    delBtn.addEventListener('click', () => {
      const col = card.closest('.column');
      card.remove();
      updateCount(col);
      saveState();
    });

    card.addEventListener('dragstart', e => {
      draggingCard = card;
      card.classList.add('dragging');
      e.dataTransfer.effectAllowed = 'move';
      e.dataTransfer.setData('text/plain', id);
    });
    card.addEventListener('dragend', () => {
      card.classList.remove('dragging');
      draggingCard = null;
    });

    card.appendChild(titleEl);
    card.appendChild(delBtn);
    return card;
  }

  function addCardToColumn(colId, id, title) {
    const containers = getContainers();
    const container = containers[colId];
    if (!container) return;
    const card = createCardEl(id, title);
    container.appendChild(card);
    updateCount(container.closest('.column'));
  }

  function setupColumns() {
    document.querySelectorAll('.column').forEach(col => {
      col.addEventListener('dragover', e => {
        e.preventDefault();
        e.dataTransfer.dropEffect = 'move';
        col.classList.add('drag-over');
      });
      col.addEventListener('dragleave', e => {
        if (!col.contains(e.relatedTarget)) {
          col.classList.remove('drag-over');
        }
      });
      col.addEventListener('drop', e => {
        e.preventDefault();
        col.classList.remove('drag-over');
        if (!draggingCard) return;
        const fromCol = draggingCard.closest('.column');
        const container = col.querySelector('.card-container');
        container.appendChild(draggingCard);
        if (fromCol && fromCol !== col) updateCount(fromCol);
        updateCount(col);
        saveState();
      });
    });
  }

  function loadState() {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return;
    try {
      const data = JSON.parse(raw);
      for (const [colId, cards] of Object.entries(data)) {
        cards.forEach(({ id, title }) => addCardToColumn(colId, id, title));
      }
    } catch (_) {}
  }

  document.getElementById('add-card').addEventListener('click', () => {
    const input = document.getElementById('new-card');
    const title = input.value.trim();
    if (!title) return;
    const id = 'card-' + Date.now() + '-' + Math.random().toString(36).slice(2, 7);
    addCardToColumn('col-todo', id, title);
    input.value = '';
    saveState();
    input.focus();
  });

  document.getElementById('new-card').addEventListener('keydown', e => {
    if (e.key === 'Enter') document.getElementById('add-card').click();
  });

  setupColumns();
  loadState();
</script>
</body>
</html>
